import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SlideData {
  id: number;
  title: string;
  subtitle?: string;
  content: React.ReactNode;
  bgClass?: string;
}

export interface ComparisonRow {
  feature: string;
  bank: string;
  mutualFund: string;
  financialPolicy: string;
  isHighlight?: boolean;
}

import React from 'react';
import { ComparisonRow } from '../types';

const rows: ComparisonRow[] = [
  { feature: "מס רווחי הון", bank: "15% (נומינלי)", mutualFund: "25% (ריאלי)", financialPolicy: "25% (ריאלי) - דחיית מס מלאה!", isHighlight: true },
  { feature: "נזילות (משיכת כסף)", bank: "מוגבלת / קנסות", mutualFund: "יומית", financialPolicy: "גבוהה (עד שבוע)", isHighlight: false },
  { feature: "מעבר בין מסלולים", bank: "סגירת פיקדון ופתיחת חדש", mutualFund: "מכירה ותשלום מס", financialPolicy: "חופשי וללא תשלום מס!", isHighlight: true },
  { feature: "ניהול מקצועי", bank: "אין", mutualFund: "יש", financialPolicy: "יש + פיזור רחב", isHighlight: false },
  { feature: "תקרת הפקדה", bank: "אין", mutualFund: "אין", financialPolicy: "אין (בשונה מקופת גמל)", isHighlight: false },
];

export const ComparisonTable: React.FC = () => {
  return (
    <div className="overflow-x-auto rounded-xl shadow-lg border border-slate-200">
      <table className="w-full text-right border-collapse bg-white">
        <thead>
          <tr className="bg-indigo-600 text-white">
            <th className="p-4 text-lg">תכונה</th>
            <th className="p-4 text-lg">פיקדון בנקאי</th>
            <th className="p-4 text-lg">קרן נאמנות</th>
            <th className="p-4 text-lg font-bold">בסט אינווסט (פוליסה פיננסית)</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((row, idx) => (
            <tr key={idx} className={`${idx % 2 === 0 ? 'bg-slate-50' : 'bg-white'} ${row.isHighlight ? 'border-r-4 border-r-green-500' : ''}`}>
              <td className="p-4 font-semibold border-b border-slate-200">{row.feature}</td>
              <td className="p-4 border-b border-slate-200">{row.bank}</td>
              <td className="p-4 border-b border-slate-200">{row.mutualFund}</td>
              <td className={`p-4 border-b border-slate-200 font-bold ${row.isHighlight ? 'text-green-700' : 'text-indigo-800'}`}>
                {row.financialPolicy}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';

const data = [
  { name: 'פיקדון בנקאי (נטו)', value: 1034000, color: '#94a3b8' },
  { name: 'בסט אינווסט (נטו)', value: 1060000, color: '#4f46e5' },
];

export const FinancialChart: React.FC = () => {
  return (
    <div className="h-[300px] w-full mt-6">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 20, right: 30, left: 40, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis domain={[1000000, 1070000]} tickFormatter={(val) => `₪${(val/1000000).toFixed(2)}M`} />
          <Tooltip formatter={(value: number) => `₪${value.toLocaleString()}`} />
          <Legend />
          <Bar dataKey="value" name="יתרה לאחר שנה">
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
      <p className="text-center text-sm text-slate-500 mt-2">* ההמחשה מניחה 4% ריבית בבנק לעומת 8% תשואה בבסט אינווסט, לאחר ניכוי מס.</p>
    </div>
  );
};

